import{_ as e,o as t,c as n,a2 as i}from"./chunks/framework.7R1OEGYz.js";const p=JSON.parse('{"title":"Accounts on this device","description":"","frontmatter":{},"headers":[],"relativePath":"using/accounts.md","filePath":"using/accounts.md"}'),o={name:"using/accounts.md"};function s(c,a,r,h,d,u){return t(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="accounts-on-this-device" tabindex="-1">Accounts on this device <a class="header-anchor" href="#accounts-on-this-device" aria-label="Permalink to &quot;Accounts on this device&quot;">​</a></h1><p>There is no logout in Suho. There are no sessions. There are accounts on this device. The sidebar identity card opens the account switcher.</p><h2 id="switching" tabindex="-1">Switching <a class="header-anchor" href="#switching" aria-label="Permalink to &quot;Switching&quot;">​</a></h2><p>The switcher lists every account this browser knows. Each row shows a seal or a gray dot, the name or address, and which passkey is linked. The current account is checked.</p><p>Tap a row to switch. Switching just changes the active account. It signs nothing.</p><h2 id="add-account" tabindex="-1">Add account <a class="header-anchor" href="#add-account" aria-label="Permalink to &quot;Add account&quot;">​</a></h2><ul><li><strong>Add account.</strong> Runs onboarding to create a new account.</li><li><strong>Add existing account.</strong> Enter the address of a Suho account you already have. The app checks that it is a real Suho account on chain, then links a passkey to it.</li></ul><h2 id="linking-a-passkey" tabindex="-1">Linking a passkey <a class="header-anchor" href="#linking-a-passkey" aria-label="Permalink to &quot;Linking a passkey&quot;">​</a></h2><p>An account with no linked passkey on this device shows a Link button. Linking is a one-time re-attach. You pick a passkey, and the app verifies its signature against the account&#39;s on-chain key before storing anything. A wrong pick is never saved and never reaches a transaction.</p><p>If no passkey on this device matches, the app offers <strong>Recover with Arise</strong>. That is the only time Arise enters a normal switch. Switching and linking never need recovery.</p><p>Linking works from a fully cleared cache. Everything is reconstructed from chain plus a passkey pick.</p><h2 id="forget-an-account" tabindex="-1">Forget an account <a class="header-anchor" href="#forget-an-account" aria-label="Permalink to &quot;Forget an account&quot;">​</a></h2><p>Each row has a small remove action, behind a confirmation. It forgets the local entry only. The account itself lives on chain. Your passkey stays in the device credential manager.</p><h2 id="about-credentials" tabindex="-1">About credentials <a class="header-anchor" href="#about-credentials" aria-label="Permalink to &quot;About credentials&quot;">​</a></h2><p>Suho stores one passkey credential id per account. It is public data, not key material. This per-account mapping is why a signature is always pinned to the right account after you switch.</p>',15)])])}const g=e(o,[["render",s]]);export{p as __pageData,g as default};
